--
-- Name: bridge_flows_7d; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.bridge_flows_7d AS
 SELECT chain,
    sum(deposits_usd) AS deposits_7d,
    sum(withdrawals_usd) AS withdrawals_7d,
    sum(net_flow_usd) AS net_flow_7d,
    avg(net_flow_usd) AS avg_daily_flow,
    count(DISTINCT date) AS days_tracked,
    max(date) AS latest_date
   FROM public.bridge_flows
  WHERE (date >= (CURRENT_DATE - '7 days'::interval))
  GROUP BY chain
  ORDER BY (sum(net_flow_usd)) DESC;


