--
-- Name: bridge_flows_latest; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.bridge_flows_latest AS
 SELECT chain,
    date,
    deposits_usd,
    withdrawals_usd,
    net_flow_usd,
    deposit_txs,
    withdraw_txs,
        CASE
            WHEN (net_flow_usd > (10000000)::numeric) THEN 'STRONG_INFLOW'::text
            WHEN (net_flow_usd > (1000000)::numeric) THEN 'MODERATE_INFLOW'::text
            WHEN (net_flow_usd < ('-10000000'::integer)::numeric) THEN 'STRONG_OUTFLOW'::text
            WHEN (net_flow_usd < ('-1000000'::integer)::numeric) THEN 'MODERATE_OUTFLOW'::text
            ELSE 'NEUTRAL'::text
        END AS flow_status
   FROM public.bridge_flows
  WHERE (((chain)::text, date) IN ( SELECT bridge_flows_1.chain,
            max(bridge_flows_1.date) AS max_date
           FROM public.bridge_flows bridge_flows_1
          GROUP BY bridge_flows_1.chain))
  ORDER BY net_flow_usd DESC;


