--
-- Name: defi_flow_alerts; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.defi_flow_alerts AS
 WITH recent_data AS (
         SELECT defi_protocols.protocol_name,
            defi_protocols.tvl_usd,
            defi_protocols.change_1d_pct,
            defi_protocols.category,
            defi_protocols.scraped_at
           FROM public.defi_protocols
          WHERE (defi_protocols.scraped_at > (now() - '01:00:00'::interval))
        )
 SELECT protocol_name,
    tvl_usd,
    change_1d_pct,
    category,
        CASE
            WHEN ((change_1d_pct > (20)::numeric) AND (tvl_usd > (100000000)::numeric)) THEN 'MASSIVE_INFLOW'::text
            WHEN ((change_1d_pct > (10)::numeric) AND (tvl_usd > (500000000)::numeric)) THEN 'LARGE_INFLOW'::text
            WHEN ((change_1d_pct < ('-20'::integer)::numeric) AND (tvl_usd > (100000000)::numeric)) THEN 'MASSIVE_OUTFLOW'::text
            WHEN ((change_1d_pct < ('-10'::integer)::numeric) AND (tvl_usd > (500000000)::numeric)) THEN 'LARGE_OUTFLOW'::text
            ELSE 'NORMAL'::text
        END AS alert_type,
    scraped_at
   FROM recent_data
  WHERE (abs(change_1d_pct) > (10)::numeric)
  ORDER BY (abs(change_1d_pct)) DESC;


