--
-- Name: defi_tvl_latest; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.defi_tvl_latest AS
 WITH latest_chains AS (
         SELECT DISTINCT ON (defi_tvl_chains.chain_name) defi_tvl_chains.chain_name,
            defi_tvl_chains.tvl_usd,
            defi_tvl_chains.scraped_at
           FROM public.defi_tvl_chains
          ORDER BY defi_tvl_chains.chain_name, defi_tvl_chains.scraped_at DESC
        ), latest_protocols AS (
         SELECT DISTINCT ON (defi_protocols.protocol_name) defi_protocols.protocol_name,
            defi_protocols.symbol,
            defi_protocols.tvl_usd,
            defi_protocols.change_1d_pct,
            defi_protocols.change_7d_pct,
            defi_protocols.category,
            defi_protocols.main_chain,
            defi_protocols.scraped_at
           FROM public.defi_protocols
          ORDER BY defi_protocols.protocol_name, defi_protocols.scraped_at DESC
        )
 SELECT ( SELECT sum(latest_chains.tvl_usd) AS sum
           FROM latest_chains) AS total_tvl,
    ( SELECT json_object_agg(latest_chains.chain_name, latest_chains.tvl_usd) AS json_object_agg
           FROM latest_chains) AS chain_breakdown,
    ( SELECT count(*) AS count
           FROM latest_protocols
          WHERE (latest_protocols.change_1d_pct > (5)::numeric)) AS protocols_gaining,
    ( SELECT count(*) AS count
           FROM latest_protocols
          WHERE (latest_protocols.change_1d_pct < ('-5'::integer)::numeric)) AS protocols_losing,
    ( SELECT max(latest_chains.scraped_at) AS max
           FROM latest_chains) AS last_updated;


ALTER VIEW public.defi_tvl_latest OWNER TO postgres;

