    tweet_text text NOT NULL,
    sentiment_score numeric(5,4),
    sentiment_label character varying(20),
    author_username character varying(100),
    author_followers integer,
    retweet_count integer DEFAULT 0,
    like_count integer DEFAULT 0,
    reply_count integer DEFAULT 0,
    quote_count integer DEFAULT 0,
    tweet_created_at timestamp with time zone,
    scraped_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    weighted_score numeric(10,4),
    alert_level character varying(20),
    is_whale boolean DEFAULT false,
    volume_spike numeric(5,2),
    bot_probability numeric(4,3),
    pump_score numeric(4,3),
    influence_weight numeric(10,4),
    source character varying(50) DEFAULT 'general_search'::character varying,
    verified boolean DEFAULT false,
    has_urls boolean DEFAULT false,
    hashtag_count integer DEFAULT 0,
    following_count integer DEFAULT 0,
    sentiment_velocity numeric(10,6),
    volume_acceleration numeric(10,6),
    momentum_score numeric(10,6),
    CONSTRAINT chk_bot_probability CHECK (((bot_probability >= (0)::numeric) AND (bot_probability <= (1)::numeric))),
    CONSTRAINT chk_influence_weight CHECK (((influence_weight >= (0)::numeric) AND (influence_weight <= (1)::numeric))),
    CONSTRAINT chk_pump_score CHECK (((pump_score >= (0)::numeric) AND (pump_score <= (1)::numeric))),
    CONSTRAINT chk_sentiment_score CHECK (((sentiment_score >= ('-1'::integer)::numeric) AND (sentiment_score <= (1)::numeric))),
    CONSTRAINT chk_volume_spike CHECK ((volume_spike >= (0)::numeric))
);


ALTER TABLE public.twitter_sentiment OWNER TO postgres;

--
-- Name: hourly_twitter_volume; Type: MATERIALIZED VIEW; Schema: public; Owner: postgres
--

CREATE MATERIALIZED VIEW public.hourly_twitter_volume AS
 SELECT date_trunc('hour'::text, scraped_at) AS hour,
    token,
    count(*) AS tweet_count,
    count(*) FILTER (WHERE (bot_probability < 0.5)) AS human_tweets,
    avg(sentiment_score) AS avg_sentiment,
    avg(
        CASE
            WHEN (bot_probability < 0.5) THEN sentiment_score
            ELSE NULL::numeric
        END) AS human_sentiment,
    max(volume_spike) AS max_volume_spike,
    avg(weighted_score) AS avg_weighted,
    max(weighted_score) AS max_weighted,
    count(*) FILTER (WHERE ((alert_level)::text = ANY ((ARRAY['HIGH'::character varying, 'EXTREME'::character varying, 'WHALE_SIGNAL'::character varying])::text[]))) AS high_impact_count
   FROM public.twitter_sentiment
  WHERE (scraped_at > (now() - '7 days'::interval))
  GROUP BY (date_trunc('hour'::text, scraped_at)), token
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.hourly_twitter_volume OWNER TO postgres;

--
-- Name: l2_rotation_rankings; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.l2_rotation_rankings AS
 WITH flow_metrics AS (
         SELECT bridge_flows.chain,
            sum(
                CASE
                    WHEN (bridge_flows.date = (CURRENT_DATE - '1 day'::interval)) THEN bridge_flows.net_flow_usd
                    ELSE (0)::numeric
                END) AS flow_24h,
            sum(
                CASE
                    WHEN (bridge_flows.date >= (CURRENT_DATE - '7 days'::interval)) THEN bridge_flows.net_flow_usd
                    ELSE (0)::numeric
                END) AS flow_7d,
            sum(
                CASE
                    WHEN (bridge_flows.date >= (CURRENT_DATE - '30 days'::interval)) THEN bridge_flows.net_flow_usd
                    ELSE (0)::numeric
                END) AS flow_30d,
                CASE
                    WHEN (count(
                    CASE
                        WHEN (bridge_flows.date >= (CURRENT_DATE - '30 days'::interval)) THEN 1
                        ELSE NULL::integer
                    END) >= 7) THEN ((sum(
                    CASE
                        WHEN (bridge_flows.date >= (CURRENT_DATE - '7 days'::interval)) THEN bridge_flows.net_flow_usd
                        ELSE (0)::numeric
                    END) / (7)::numeric) / NULLIF((sum(
                    CASE
                        WHEN (bridge_flows.date >= (CURRENT_DATE - '30 days'::interval)) THEN bridge_flows.net_flow_usd
                        ELSE (0)::numeric
                    END) / (30)::numeric), (0)::numeric))
                    ELSE NULL::numeric
                END AS velocity_ratio
           FROM public.bridge_flows
          WHERE (bridge_flows.date >= (CURRENT_DATE - '30 days'::interval))
          GROUP BY bridge_flows.chain
        )
 SELECT chain,
    flow_24h,
    flow_7d,
    flow_30d,
    velocity_ratio,
    rank() OVER (ORDER BY flow_7d DESC) AS flow_rank_7d,
        CASE
            WHEN (flow_7d > (50000000)::numeric) THEN 'HOT'::text
            WHEN (flow_7d > (10000000)::numeric) THEN 'WARMING'::text
            WHEN (flow_7d < ('-10000000'::integer)::numeric) THEN 'COOLING'::text
            WHEN (flow_7d < ('-50000000'::integer)::numeric) THEN 'COLD'::text
            ELSE 'NEUTRAL'::text
        END AS rotation_status
   FROM flow_metrics
  ORDER BY flow_7d DESC;


ALTER VIEW public.l2_rotation_rankings OWNER TO postgres;

--
-- Name: VIEW l2_rotation_rankings; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.l2_rotation_rankings IS 'Use this view to identify which L2s are gaining/losing capital';


