--
-- Name: options_volatility; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.options_volatility (
    id integer NOT NULL,
    btc_iv numeric(10,2),
    btc_dvol numeric(10,2),
    btc_skew numeric(10,2),
    btc_iv_rank numeric(5,2),
    eth_iv numeric(10,2),
    eth_dvol numeric(10,2),
    eth_skew numeric(10,2),
    eth_iv_rank numeric(5,2),
    avg_iv numeric(10,2),
    volatility_regime character varying(20),
    directional_bias character varying(20),
    risk_level character varying(20),
    position_adjustment numeric(5,3),
    scraped_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT risk_level_check CHECK (((risk_level)::text = ANY ((ARRAY['HIGH'::character varying, 'MODERATE'::character varying, 'LOW'::character varying, 'NORMAL'::character varying])::text[]))),
    CONSTRAINT vol_regime_check CHECK (((volatility_regime)::text = ANY ((ARRAY['EXTREME'::character varying, 'HIGH'::character varying, 'MODERATE'::character varying, 'LOW'::character varying])::text[])))
);


ALTER TABLE public.options_volatility OWNER TO postgres;

--
-- Name: options_volatility_alerts; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.options_volatility_alerts AS
 SELECT avg_iv,
    volatility_regime,
    directional_bias,
    risk_level,
    position_adjustment,
        CASE
            WHEN (avg_iv > (80)::numeric) THEN 'EXTREME: IV above 80, reduce all positions'::text
            WHEN (avg_iv > (65)::numeric) THEN 'HIGH: Elevated volatility, reduce position sizes'::text
            WHEN ((btc_skew < ('-8'::integer)::numeric) OR (eth_skew < ('-8'::integer)::numeric)) THEN 'SKEW: Heavy put buying detected'::text
            WHEN ((risk_level)::text = 'HIGH'::text) THEN 'RISK: High volatility risk conditions'::text
            ELSE NULL::text
        END AS alert_message,
    scraped_at
   FROM public.options_volatility
  WHERE ((scraped_at > (now() - '01:00:00'::interval)) AND (((risk_level)::text = ANY ((ARRAY['HIGH'::character varying, 'MODERATE'::character varying])::text[])) OR (avg_iv > (65)::numeric) OR (btc_skew < ('-8'::integer)::numeric) OR (eth_skew < ('-8'::integer)::numeric)))
  ORDER BY scraped_at DESC;


ALTER VIEW public.options_volatility_alerts OWNER TO postgres;

