--
-- Name: recent_volume_spikes; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.recent_volume_spikes AS
 SELECT token,
    (date_trunc('minute'::text, scraped_at) - ((((EXTRACT(minute FROM scraped_at))::integer % 5))::double precision * '00:01:00'::interval)) AS interval_5min,
    count(*) AS tweet_count,
    max(volume_spike) AS max_spike,
    avg(sentiment_score) AS avg_sentiment,
    avg(
        CASE
            WHEN (bot_probability < 0.5) THEN sentiment_score
            ELSE NULL::numeric
        END) AS human_sentiment,
    count(*) FILTER (WHERE (bot_probability >= 0.7)) AS bot_count,
    count(*) FILTER (WHERE (is_whale = true)) AS whale_count
   FROM public.twitter_sentiment
  WHERE (scraped_at > (now() - '01:00:00'::interval))
  GROUP BY token, (date_trunc('minute'::text, scraped_at) - ((((EXTRACT(minute FROM scraped_at))::integer % 5))::double precision * '00:01:00'::interval))
 HAVING (count(*) > 5)
  ORDER BY (max(volume_spike)) DESC NULLS LAST, (date_trunc('minute'::text, scraped_at) - ((((EXTRACT(minute FROM scraped_at))::integer % 5))::double precision * '00:01:00'::interval)) DESC;


ALTER VIEW public.recent_volume_spikes OWNER TO postgres;

