--
-- Name: twitter_trading_signals; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.twitter_trading_signals AS
 SELECT token,
    max(volume_spike) AS volume_signal,
    avg(
        CASE
            WHEN (bot_probability < 0.3) THEN sentiment_score
            ELSE NULL::numeric
        END) AS quality_sentiment,
    count(*) FILTER (WHERE ((alert_level)::text = ANY ((ARRAY['HIGH'::character varying, 'EXTREME'::character varying, 'WHALE_SIGNAL'::character varying])::text[]))) AS high_impact_tweets,
    max(
        CASE
            WHEN (pump_score IS NOT NULL) THEN pump_score
            ELSE NULL::numeric
        END) AS pump_risk,
        CASE
            WHEN ((max(volume_spike) >= 3.0) AND (avg(
            CASE
                WHEN (bot_probability < 0.3) THEN sentiment_score
                ELSE NULL::numeric
            END) > 0.2)) THEN 'STRONG BUY'::text
            WHEN ((max(volume_spike) >= 2.0) AND (avg(
            CASE
                WHEN (bot_probability < 0.3) THEN sentiment_score
                ELSE NULL::numeric
            END) > 0.1)) THEN 'BUY'::text
            WHEN ((max(volume_spike) >= 2.0) AND (avg(
            CASE
                WHEN (bot_probability < 0.3) THEN sentiment_score
                ELSE NULL::numeric
            END) < '-0.2'::numeric)) THEN 'SELL'::text
            WHEN (max(pump_score) >= 0.7) THEN 'PUMP WARNING'::text
            ELSE 'HOLD'::text
        END AS signal,
    count(*) AS total_tweets,
    now() AS signal_time
   FROM public.twitter_sentiment
  WHERE (scraped_at > (now() - '00:15:00'::interval))
  GROUP BY token
 HAVING (count(*) >= 5);


ALTER VIEW public.twitter_trading_signals OWNER TO postgres;

